getByPlatform(platform: ChannelPlatform): ChannelRegistryEntry | undefined {
    return this.entries.get(platform)
  }

register(channel: Channel, config: ChannelConfig): void {
    if (this.entries.has(channel.platform)) {
      throw new Error(`Channel for platform "${channel.platform}" is already registered`)
    }
    this.entries.set(channel.platform, { channel, config, registeredAt: new Date() })

constructor(config: SlackConfig, deps?: SlackChannelDeps) {
    this.config = config
    this.deps = deps ?? null
  }

export interface ChannelOperationResult {
  success: boolean
  error?: Error
}
